import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer, CloudLightning, CloudSnow, Eye, Calendar, Clock } from 'lucide-react';
import './App.css';

const API_KEY = "1d30e0668b384c4d133dc45fe617b03b"; 

function App() {
  const [city, setCity] = useState('Visnagar');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [hourlyData, setHourlyData] = useState([]);
  const [aqi, setAqi] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      const { lat, lon } = currentRes.data.coord;

      const aqiRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/air_pollution?lat=${lat}&lon=${lon}&appid=${API_KEY}`
      );
      setAqi(aqiRes.data.list[0].main.aqi);

      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      setHourlyData(forecastRes.data.list.slice(0, 5)); 
      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

    } catch (err) {
      setError('કનેક્શન એરર અથવા ખોટું સિટી નામ.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  const getWeatherIcon = (main, size = 40) => {
    switch (main) {
      case 'Clear': return <Sun className="cyber-glow text-amber" size={size} />;
      case 'Clouds': return <Cloud className="cyber-glow text-slate" size={size} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="cyber-glow text-cyan" size={size} />;
      case 'Thunderstorm': return <CloudLightning className="cyber-glow text-purple" size={size} />;
      case 'Snow': return <CloudSnow className="cyber-glow text-blue" size={size} />;
      default: return <Sun className="cyber-glow text-amber" size={size} />;
    }
  };

  return (
    <div className="sci-fi-weather-portal">
      <div className="cosmic-background"></div>

      <div className="master-glass-frame">
        {/* Top Control Header */}
        <div className="portal-header">
          <form onSubmit={handleSearch} className="cyber-search">
            <input 
              type="text" 
              placeholder="સિટીનું નામ લખો..." 
              value={city}
              onChange={(e) => setCity(e.target.value)}
            />
            <button type="submit"><Search size={16} /></button>
          </form>
        </div>

        {loading && <div className="portal-msg">ડેટા કનેક્ટ થઈ રહ્યો છે...</div>}
        {error && <div className="portal-msg error-msg">{error}</div>}

        {weatherData && !loading && !error && (
          <div className="portal-grid-body">

            {/* LEFT BANNER: GIANT WEATHER IMAGE & TEMP */}
            <div className="panel-left-hero">
              <h1 className="geo-title">{weatherData.name}, <span>{weatherData.sys.country}</span></h1>

              <div className="giant-vibe-container">
                {getWeatherIcon(weatherData.weather[0].main, 140)}
                <div className="giant-temp-block">
                  <h2>{Math.round(weatherData.main.temp)}°C</h2>
                  <p>{weatherData.weather[0].description.toUpperCase()}</p>
                </div>
              </div>
            </div>

            {/* RIGHT BANNER: PODIUMS & DETAILS */}
            <div className="panel-right-details">

              {/* Premium 3D Podiums */}
              <div className="podium-row">
                <div className="podium-card">
                  <div className="podium-base">
                    <Thermometer size={24} className="podium-icon neon-amber" />
                    <span className="p-val">{Math.round(weatherData.main.feels_like)}°C</span>
                  </div>
                  <span className="p-label">અનુભવ</span>
                </div>

                <div className="podium-card">
                  <div className="podium-base">
                    <Droplets size={24} className="podium-icon neon-cyan" />
                    <span className="p-val">{weatherData.main.humidity}%</span>
                  </div>
                  <span className="p-label">ભેજ</span>
                </div>

                <div className="podium-card">
                  <div className="podium-base">
                    <Wind size={24} className="podium-icon neon-purple" />
                    <span className="p-val">{weatherData.wind.speed} <small>m/s</small></span>
                  </div>
                  <span className="p-label">પવન ગતિ</span>
                </div>
              </div>

              {/* Weekly Extended Stream */}
              <div className="extended-forecast-box">
                <h3>આગામી દિવસોની આગાહી</h3>
                <div className="forecast-flex-grid">
                  {forecastData.map((day, idx) => (
                    <div key={idx} className="forecast-cyber-tile">
                      <span className="tile-day">
                        {new Date(day.dt * 1000).toLocaleDateString('en-US', { weekday: 'short' })}
                      </span>
                      <div className="tile-icon-wrap">
                        {getWeatherIcon(day.weather[0].main, 28)}
                      </div>
                      <span className="tile-temp">{Math.round(day.main.temp)}°C</span>
                      <div className="tile-line-indicator"></div>
                    </div>
                  ))}
                </div>
              </div>

            </div>

          </div>
        )}
      </div>
    </div>
  );
}

export default App;
